const body = $input.first().json;
let accion = '', chatId = '', userId = '', userName = '';
let callbackData = '', messageText = '', callbackQueryId = '';
if (body.callback_query) {
  callbackData = (body.callback_query.data || '').trim();
  chatId = String(body.callback_query.message.chat.id);
  userId = String(body.callback_query.from.id);
  userName = body.callback_query.from.first_name || 'Cliente';
  callbackQueryId = body.callback_query.id;
} else if (body.message) {
  messageText = (body.message.text || '').toLowerCase().trim();
  chatId = String(body.message.chat.id);
  userId = String(body.message.from.id);
  userName = body.message.from.first_name || 'Cliente';
}
const saludos = ['hola','hi','hello','buenas','buenos','buen','hey','inicio','start','menu','menú','empezar','comenzar','ayuda','help','pedido','quiero','necesito','orden'];
if (messageText === '/start' || saludos.some(s => messageText.includes(s))) { accion = 'menu_principal'; }
else if (callbackData === 'menu_principal' || callbackData === 'inicio') { accion = 'menu_principal'; }
else if (callbackData === 'iniciar_pedido' || callbackData === 'categorias') { accion = 'categorias'; }
else if (callbackData.startsWith('cat_')) { accion = 'productos'; }
else if (callbackData.startsWith('prod_')) { accion = 'agregar_carrito'; }
else if (callbackData === 'ver_carrito') { accion = 'ver_carrito'; }
else if (callbackData === 'confirmar_pedido') { accion = 'confirmar'; }
else if (callbackData === 'limpiar_carrito') { accion = 'limpiar_carrito'; }
else if (callbackData.startsWith('estado_')) { accion = 'cambiar_estado'; }
else if (callbackData === 'mis_pedidos') { accion = 'mis_pedidos'; }
else if (callbackData === 'ayuda') { accion = 'ayuda'; }
else if (callbackData === 'promociones') { accion = 'promociones'; }
else if (messageText !== '') { accion = 'menu_principal'; }
else { accion = 'menu_principal'; }
let categoria = '', productoId = '', pedidoId = '', nuevoEstado = '';
if (callbackData.startsWith('cat_')) categoria = callbackData.replace('cat_', '');
if (callbackData.startsWith('prod_')) productoId = callbackData.replace('prod_', '');
if (callbackData.startsWith('estado_')) {
  const partes = callbackData.split('_');
  nuevoEstado = partes[1];
  pedidoId = partes.slice(2).join('_');
}
return [{ json: { accion, chatId, userId, userName, callbackData, messageText, callbackQueryId, categoria, productoId, pedidoId, nuevoEstado, rawBody: body } }];

const items = $input.all();
const routerData = $('Router Principal').first().json;
const chatId = routerData.chatId;
const categoria = routerData.categoria;
const emojiCat = { bebidas: '☕', almuerzos: '🍱', snacks: '🍿' };
const emoji = emojiCat[categoria] || '🍽';
const cap = categoria.charAt(0).toUpperCase() + categoria.slice(1);
const disponibles = items.filter(i => parseInt(i.json.stock) > 0);
let texto = emoji + ' *Menu - ' + cap + '*\n\n';
const botones = [];
disponibles.forEach((item, idx) => {
  const p = item.json;
  const precio = parseInt(p.precio).toLocaleString('es-CO');
  texto += (idx+1) + '. *' + p.nombre + '* - $' + precio + '\n   ' + p.descripcion + '\n\n';
  botones.push([{ text: (idx+1) + '. ' + p.nombre + ' - $' + precio, callback_data: 'prod_' + p.id_producto }]);
});
botones.push([
  { text: '🛒 Ver Carrito', callback_data: 'ver_carrito' },
  { text: '🏠 Menu Principal', callback_data: 'menu_principal' }
]);
return [{ json: {
  chatId,
  textProductos: texto,
  reply_markup: JSON.stringify({ inline_keyboard: botones })
}}];

const routerData = $('Router Principal').first().json;
const userId = routerData.userId;
const chatId = routerData.chatId;
const userName = routerData.userName;
const productoId = routerData.productoId;
const sesionItems = $input.all();
let carrito = [];
try {
  if (sesionItems.length > 0 && sesionItems[0].json && sesionItems[0].json.carrito_temporal) {
    const raw = sesionItems[0].json.carrito_temporal;
    if (raw && raw.trim() !== '' && raw.trim() !== '[]') {
      carrito = JSON.parse(raw);
    }
  }
} catch(e) { carrito = []; }
if (!Array.isArray(carrito)) carrito = [];
const itemExistente = carrito.find(i => i.id === productoId);
if (itemExistente) { itemExistente.cantidad += 1; }
else { carrito.push({ id: productoId, cantidad: 1 }); }
const totalItems = carrito.reduce((sum, i) => sum + i.cantidad, 0);
return [{ json: {
  userId, chatId, userName, productoId,
  carrito: JSON.stringify(carrito),
  pantalla_actual: 'carrito',
  ultimo_cambio: new Date().toISOString(),
  ultimo_pedido_id: '',
  totalItems
}}];

const routerData = $('Router Principal').first().json;
const userId = routerData.userId;
const chatId = routerData.chatId;
const userName = routerData.userName;
const menuItems = $('Leer Precios Menu').all();

// Leer sesion - puede venir vacía si es primera vez
let sesionData = {};
try { sesionData = $('Leer Sesion Confirmar').first().json; } catch(e) { sesionData = {}; }

let carrito = [];
try {
  const raw = sesionData.carrito_temporal || '[]';
  carrito = JSON.parse(raw);
} catch(e) { carrito = []; }

if (!Array.isArray(carrito) || carrito.length === 0) {
  return [{ json: { chatId, error: 'carrito_vacio', userId } }];
}

const menuMap = {};
for (const item of menuItems) { menuMap[item.json.id_producto] = item.json; }

let subtotal = 0;
let detallesTexto = '';
const detallesArray = [];

for (const item of carrito) {
  const producto = menuMap[item.id];
  if (producto) {
    const precio = parseInt(producto.precio);
    const subtotalItem = precio * item.cantidad;
    subtotal += subtotalItem;
    detallesTexto += '• ' + producto.nombre + ' x' + item.cantidad + ' = $' + subtotalItem.toLocaleString('es-CO') + '\n';
    detallesArray.push(producto.nombre + ' x' + item.cantidad);
  }
}

const total = subtotal;
const ahora = new Date();
const fecha = ahora.toLocaleDateString('es-CO');
const hora = ahora.toLocaleTimeString('es-CO', { hour: '2-digit', minute: '2-digit' });
const fechaId = ahora.toISOString().split('T')[0].replace(/-/g, '');
const random = Math.floor(Math.random() * 90000) + 10000;
const idPedido = 'PED-' + fechaId + '-' + random;

const resumen = '🧾 *Resumen de tu Pedido*\n\n' + detallesTexto + '\n💰 *TOTAL: $' + total.toLocaleString('es-CO') + '*\n\n📋 N° Pedido: ' + idPedido + '\n⏰ ' + hora;

return [{ json: { chatId, userId, userName, idPedido, detalles: detallesArray.join(' | '), detallesTexto, total, subtotal, iva: 0, fecha, hora, resumen, estado: 'Recibido', error: null } }];

