const data = $input.first().json;
const estadoMap = {
  'preparacion': { texto: 'En Preparacion', emoji: '\U0001f468\u200d\U0001f373', msg: 'Tu pedido esta siendo preparado. \u00a1Pronto estara listo!' },
  'camino': { texto: 'En Camino', emoji: '\U0001f6f5', msg: 'Tu pedido va en camino. \u00a1Ya casi llega!' },
  'entregado': { texto: 'Entregado', emoji: '\u2705', msg: '\u00a1Tu pedido fue entregado! Esperamos que lo disfrutes.' }
};
const info = estadoMap[data.nuevoEstado] || { texto: data.nuevoEstado, emoji: '\U0001f4cb', msg: 'Estado actualizado.' };
return [{ json: { chatId: data.chatId, pedidoId: data.pedidoId, nuevoEstado: info.texto, emoji: info.emoji, mensaje: info.msg, userId: data.userId } }];

const routerData = $('Router Principal').first().json;
const sesionItems = $('Leer Sesión Ver Carrito').all();
const menuItems = $('Leer Menú Ver Carrito').all();
const chatId = routerData.chatId;
let carrito = [];
if (sesionItems.length > 0 && sesionItems[0].json.telegram_id) {
  try { carrito = JSON.parse(sesionItems[0].json.carrito_temporal || '[]'); } catch(e) { carrito = []; }
}
const menuMap = {};
for (const item of menuItems) { menuMap[item.json.id_producto] = item.json; }
if (carrito.length === 0) {
  return [{ json: { chatId, texto: '🛒 *Tu carrito está vacío*\n\nExplora nuestro menú y agrega productos.', vacio: true } }];
}
let texto = '🛒 *Tu Carrito:*\n\n';
let subtotal = 0;
for (const item of carrito) {
  const prod = menuMap[item.id];
  if (prod) {
    const precio = parseInt(prod.precio);
    const st = precio * item.cantidad;
    subtotal += st;
    texto += '• *' + prod.nombre + '* x' + item.cantidad + ' = $' + st.toLocaleString('es-CO') + '\n';
  }
}
texto += '\n💰 *TOTAL: $' + subtotal.toLocaleString('es-CO') + '*';
return [{ json: { chatId, texto, vacio: false } }];

const routerData = $('Router Principal').first().json;
const pedidosItems = $input.all();
const chatId = routerData.chatId;
if (pedidosItems.length === 0 || !pedidosItems[0].json.id_pedido) {
  return [{ json: { chatId, texto: '\U0001f4e6 *Mis Pedidos*\n\nAun no tienes pedidos registrados.\n\n\u00a1Haz tu primer pedido ahora!' } }];
}
const ultimos = pedidosItems.filter(p => p.json.id_usuario === routerData.userId).slice(-5).reverse();
if (ultimos.length === 0) { return [{ json: { chatId, texto: '\U0001f4e6 No tienes pedidos aun.' } }]; }
let texto = '\U0001f4e6 *Mis ultimos pedidos:*\n\n';
const estadoEmoji = { 'Recibido': '\U0001f4e5', 'En Preparacion': '\U0001f468\u200d\U0001f373', 'En Camino': '\U0001f6f5', 'Entregado': '\u2705' };
for (const p of ultimos) {
  const pd = p.json;
  const emoji = estadoEmoji[pd.estado] || '\U0001f4cb';
  texto += emoji + ' *' + pd.id_pedido + '*\n\U0001f4b0 $' + pd.total_pago + ' | ' + pd.estado + '\n\n';
}
return [{ json: { chatId, texto } }];
